INSERT INTO `chapters` VALUES (1,1,'Isang Pagtitipon','Magtatapos ang Oktubre nang magpahapunan si Don Santiago de los Santos, kilala sa payaw na Kapitan Tiago...','2026-04-24 21:47:25'),(2,2,'Si Crisostomo Ibarra','Dumating si Crisostomo Ibarra kasama si Kapitan Tiago sa gitna ng pagtitipon. Lahat ay nagulat sa kaniyang pagdating mula sa Europa.','2026-04-24 21:47:25'),(3,3,'Ang Hapunan','Sa hapunan, nagkaroon ng pagtatalo sa pagitan nina Padre Damaso at ng Tenyente tungkol sa nangyari sa San Diego.','2026-04-24 21:47:25'),(4,4,'Erehe at Filibustero','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(5,5,'Isang Bituin sa Gabing Madilim','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(6,6,'Si Kapitan Tiago','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(7,7,'Suyuan sa Isang Asotea','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(8,8,'Mga Alaala','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(9,9,'Mga Bagay-bagay sa Paligid','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(10,10,'Bayan ng San Diego','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(11,11,'Mga Hari-harian','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(12,12,'Todos Los Santos','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(13,13,'Mga Banta ng Unos','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(14,14,'Tasiong Baliw o Pilosopo','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(15,15,'Mga Sakristan','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(16,16,'Sisa','Ang nilalaman ng kabanatang ito ay paparating pa lamang.','2026-04-24 21:47:25'),(17,17,'Basilio','Ang nilalaman ng kabanatang ito ay pa