INSERT INTO `glossary` VALUES (16,62,'Balete','Malaking punongkahoy (genus Ficus) na may maraming baging at kilalá sa mga alamat bílang tahanan ng mga lamanlupa.',NULL),(17,62,'Sumalunga','Pagsalungat sa kilos, daloy, o puwersa (tulad agos, hangin, pababang daan, at paghihirap).',NULL),(18,62,'Ingkong','Amá o amain ng magulang ng sinuman.',NULL),(19,62,'Malumbay','Matinding kalungkutan (tulad ng nararamdaman dahil sa kasawian).',NULL),(20,62,'Pagtangis','Malakas na pag-iyak kung nagdadalamhati.',NULL),(21,62,'Bulalas','Anumang biglang pagsasalita o pag-iingay (lalo na dahil sa matinding damdámin).',NULL),(22,62,'Isinusuplong','kilos ng paglalantad o pagpapaalam ng isang maling gawain, lihim, o kasalanan sa isang nakatataas o may kapangyarihan',NULL),(23,62,'Kanser','Ito ay anumang matinding problema sa lipunan—tulad ng korapsyon o kawalan ng katarungan—na unti-unting sumisira sa bayan.',NULL),(24,62,'Paglibak','Pagpuna sa kapuwa upang maliitin at insultuhin.',NULL),(25,62,'Saklot','Pagsunggab sa isang bagay na ibig agawin o kunin.',NULL),(26,62,'Sakate','damo na ginagamit bilang pagkain ng mga hayop, lalo na para sa mga kabayo, kalabaw, o baka.',NULL),(27,62,'Polvorista','ang deposito ng mga pulbura at paputok.',NULL),(28,62,'Lunday','Maliit na bangka para sa isang tao lámang.',NULL),(29,62,'Sapantaha','Hula, hinala, o palagay na walang sapat ebidensya.',NULL),(30,62,'Oidor','Isang makapangyarihang hukom o mataas na opisyal sa korte noong panahon ng Espanyol.',NULL),(31,62,'Lebita','Isang pormal na suot ng mga prominenteng lalaki noon.',NULL),(32,62,'kuwidaw','nagpapahiwatig ng babala o pag-iingat',NULL),(33,62,'Ilog Beata','makasaysayang ilog sa Pandacan na naging tagpuan ng pag-iibigan nina Balagtas at Selya.',NULL),(34,62,'Tamasahin','Pagdanas ng kasiyahan o pakinabang na dulot ng kasaganaan, ginhawa, o yaman.',NULL),(35,62,'tikin','Isang mahabang kawayan na pangtulak ng bangka sa mababaw na lugar.',NULL),(36,62,'Napakapanglaw','masidhi o matinding paglalarawan ng kalungkutan, katahimikan, o kadiliman.',NULL),(37,62,'basyong','Isang bakanteng lalagyan o basyong kinalabasan ng isang bagay (tulad ng bala o bote).',NULL),(38,62,'nagbunsod','nagtulak o nag-udyok.',NULL),(39,62,'pagmunian','pag-iisip, pagninilay, o pagsusuri sa isang bagay bago gumawa ng desisyon.',NULL),(40,62,'said','ang punto kung saan wala na talagang natitira; sagad na sagad na.',NULL),(41,62,'manangis','Umiiyak nang matindi.',NULL),(42,62,'uyam','Pangungutya o sarkasmo.',NULL),(43,62,'Heswita','Isang orden ng mga paring Katoliko.',NULL),(44,62,'pinapaikpik','pag-ipit, o pagpapaigting sa isang bagay para maging mas siksik o tahimik.',NULL),(45,62,'karabinero','Kawal o guwardiyang tagabantay',NULL),(46,62,'pumupusyaw','paglabo o pagkawala ng tindi ng kulay.',NULL),(47,62,'falua','isang mabilis na bangkang pang-patrolya ng mga awtoridad.',NULL),(48,62,'kapasete','matigas na sumbrero na suot ng mga sundalo o guwardiya sibil bilang proteksyon sa ulo.',NULL),(49,62,'bayoneta','mahabang patalim o kutsilyo na ikinakabit sa dulo ng nguso ng baril',NULL),(50,62,'Pipit','Isang napakaliit na ibon; ginagamit na metapora para sa taong walang laban o madaling apihin.',NULL),(51,62,'tsisis','Tunog ng pagsutsot ng mainit na bagay sa tubig.',NULL),(52,62,'Nilagpakan','pagbagsak o pagtama ng isang bagay',NULL),(53,62,'punglo','Bala ng baril',NULL),(139,63,'saserdote','Lumang tawag sa pari, karaniwang sa Bibliya.','Ginamit ito upang ilarawan ang katungkulan ni Padre Damaso bilang isang pari.'),(140,63,'napoot','labis na nagalit o nagkaroon ng matinding galit','Tumutukoy sa galit ni Padre Damaso sa mga taong kumokontra sa kaniyang nais.'),(141,63,'disgustilyo','mga hinanakit o maliliit na sama ng loob','Ang mga maliliit na tampo ni Maria Clara noong siya ay bata pa.'),(142,63,'pelus','Telang mabalahibo na yarì sa seda, nylon, rayon, atbp. na pawang masinsin ang pagkakahábi at may makapal na rabáw.','Inilalarawan ang marangyang lalagyan ng mga alahas ni Maria Clara.'),(143,63,'mongha','Babaeng naninirahan sa kumbento upang iukol ang kaniyang búhay sa pagsamba at pagdalangin sa Diyos.','Ito ang piniling landas ni Maria Clara matapos mabalitang patay na si Ibarra.'),(144,63,'daing','Pagpapahayag ng lungkot, sakít, hindi kasiyahan, samâ-ng-loob, at katulad na damdámin.','Ang mga hiling at panalangin sa loob ng kumbento.'),(145,63,'esposa','Asawang babae.','Ginamit ni Padre Damaso upang ilarawan ang magiging buhay ni Maria Clara kung magpapakasal.'),(146,63,'binubusabos','inaapi, pinapahirapan, o minamaliit','Ang kinatatakutang tadhana ni Padre Damaso para sa mga magiging anak ni Maria Clara.'),(147,63,'napaigtad','Biglang napakilos o napatayo dahil sa gulat','Ang reaksyon ni Maria Clara nang gulatin siya ni Padre Damaso.'),(148,63,'estutseng','kahon ng alahas, lalagyan ng mamahaling bagay.','Ang mga lalagyan ng regalong pangkasal na hindi pinapansin ni Maria Clara.'),(149,63,'bulalas','Anumang biglang pagsasalita o pag-iingay (lalo na dahil sa matinding damdámin).','Ang biglang sigaw o pahayag ni Padre Damaso sa gitna ng pag-uusap.'),(150,63,'ligalig','Magulo ang isipan kayâ hindi mapirme.','Inilalarawan ang nararamdaman ni Maria Clara dahil sa kaniyang mga problema.'),(151,63,'sawiin','biguin o sirain ang inaasam na kaligayahan','Ang pakiusap ni Maria Clara sa kaniyang ninong.'),(152,63,'manyikang sahing','simpleng manikang gawa sa abo o uling','Isang alaala ng pagkabata ni Maria Clara.'),(153,63,'tigmak','Lubhang basâ ng anumang likido, lalo na kung tubig-ulan, páwis, o dugo.','Inilalarawan ang mga matang basang-basa sa luha.'),(154,63,'kapritso','Paggawa o paghingi ng anuman nang walang kadahilanan o batayan kundi para sa sariling kiya.','Ang mga hiling ni Maria Clara na laging sinusunod ni Padre Damaso.'),(155,63,'seda','Pino at makintab na hiblang mula sa pugad ng isang uri ng uod.','Isa sa mga mamahaling tela na bahagi ng mga regalo para sa kasal.'),(156,64,'Libis','Makitid na kapatagang nasa pagitan ng isang bundok at iba pang mataas na lupa.','Ang lokasyon ng dampa nina Basilio sa kagubatan.'),(157,64,'Ingkong','Magalang na pagtawag sa lolo o isang matandang lalaki.','Ang matandang kumupkop kay Basilio matapos siyang sugatan.'),(158,64,'Tumitimo','tumusok, tumagos, bumaon, o nagmarka','Inilalarawan ang malalim na tingin ni Basilio dahil sa hapis.'),(159,64,'Hawas','Anyo ng mukha na mahaba at patulis ang baba (hugis itlog).','Ang anyo ng mukha ni Basilio na namana niya sa kaniyang ina.'),(160,64,'Dayap','Isang uri ng sitrus; ginagamit na pampabango o sangkap.','Ginamit bilang bahagi ng panggamot sa sugat ni Basilio.'),(161,64,'Dampa','maliit na tahanang tinitirhan ng mga maralita.','Ang payak na tahanan sa gitna ng gubat.'),(162,64,'Pikô','Laro na may batóng initsa sa ginuhitang lapag.','Ang larong nais laruin ng mga bata kasama si Basilio.'),(163,64,'Magaralgal','Nanginginig o garalgal na boses, karaniwang dahil sa pagpipigil ng iyak.','Ang tinig ng mga bata habang nagpapaalam.'),(164,64,'Hapis','Matinding dusa, lungkot, o pait na nararanasan ng kalooban.','Ang nararamdaman ni Basilio sa pagkawala ng kaniyang pamilya.'),(165,64,'Sinawata','Pinigil, sinaway, o hinadlangan ang isang kilos o pangyayari.','Ang pagpigil ni Basilio sa kaniyang sariling panginginig.'),(166,64,'Sawimpalad','nasa masamang kalagayan o nagdurusa; taong bigo o nakaranas ng malaking trahedya.','Tumutukoy sa kalagayan ni Basilio at ng kaniyang ina.'),(167,64,'Kasibulan','Panahon ng kabataan o kasariwaan.','Ang anyo ng babaeng nakita ni Sisa sa bintana.'),(168,64,'Lipos','pagiging puno ng espasyo o sisidlan','Lipos ng takot na tumakbo si Sisa nang makita ang sundalo.'),(169,64,'Nangangaligkig','matinding panginginig ng buong katawan sanhi ng labis na ginaw.','Ang nararamdaman ng mga tao sa San Diego dahil sa hanging Hilaga.'),(170,64,'Binalisunsong','ginawa o ititnupi sa hugis balisunsong o apa','Ginamit ni Basilio ang dahon ng saging upang kumuha ng tubig.'),(171,64,'Rebentador','uri ng paputok na may malakas na pagsabog','Ang hiling ng batang lalaki para sa Pasko.'),(172,64,'Nochebuena','gabi ng bisperas ng Pasko','Ang gabi kung kailan naganap ang huling pagkikita nina Basilio at Sisa.'),(173,64,'Entresuwelo','maliit o mababang silid/palapag','Dito nag-uusap sina Kapitan Basilio at Don Filipo.'),(174,64,'Kompete','uri ng paputok na pumapailanlang sa itaas bago sumabog; kwitis','Bahagi ng tradisyunal na pagdiriwang ng Pasko.'),(175,64,'Palara','manipis, makintab, at metalikong papel na ginagamit pambalot o pandekorasyon','Dekorasyon para sa Pasko.'),(176,64,'Sukal','Mga dumi o damong hindi kailangan; maaari ring tumukoy sa gulo ng nararamdaman.','Ang mga balakid sa pagtakbo nina Basilio sa gubat.'),(177,64,'Palumpong','Lupon ng maliliit na puno o halaman na tumutubong magkakasama.','Mga halaman sa loob ng mahiwagang gubat.'),(178,64,'Dawag','matinik at malakahoy na halamang-baging','Mga balakid sa kagubatan.'),(179,64,'Nilawag','Niliwanagan o nilakbay nang may dalang ilaw upang makita ang dinadaanan.','Ang mga bahagi ng gubat na natatamaan ng sinag ng buwan.'),(180,64,'Tumutugaygay','Nagmamasid o sumusubaybay nang masusi sa bawat kilos.','Ang pagbabantay ni Basilio sa kaniyang ina.'),(181,64,'Balete','malaking punongkahoy na may maraming baging.','Ang mahiwagang puno kung saan namatay si Sisa.'),(182,64,'Puminid','pagsara ng pinto; sa konteksto ng kamatayan, ang huling pagpikit ng mga mata.','Ang pagtulak ni Sisa sa pinto upang hindi makapasok si Basilio.'),(183,64,'Niyapos','Niyakap nang buong higpit at pagmamahal','Ang huling yakap ni Basilio sa kaniyang ina.'),(184,64,'Rehas','mga bakal na nakaharang sa bintana','Dito nakadungaw ang mga dalaga habang nag-uusap.'),(185,64,'Kuwartel','tirahan ng mga sundalo o guwardiya sibil','Ang lugar na iniwasan ni Sisa.'),(186,64,'Pinupog','Paulit-ulit na ginawa ang isang bagay','Ang paghalik ni Basilio sa kaniyang ina.'),(187,64,'Alipato','maliliit na bagang inililipad ng hangin mula sa nasusunog na bagay','Ang kislap ng alaala sa isip ni Sisa bago siya mamatay.'),(188,64,'Kamaksi','Isang uri ng ibon (nightjar) na karaniwang naririnig ang huni sa gabi.','Ang naririnig na huni sa gitna ng katahimikan ng gabi.'),(189,64,'Batalan','Bahagi ng bahay-kubo kung saan naghuhugas at naglilinis.','Dito nakita ni Hermana Rufa ang usok mula sa gubat.');

#
# Structure for table "quizzes"
#

DROP TABLE IF EXISTS `quizzes`;
CREATE TABLE `quizzes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `chapter_id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `chapter_id` (`chapter_id`),
  CONSTRAINT `quizzes_ibfk_1` FOREIGN KEY (`chapter_id`) REFERENCES `chapters` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

#
# Data for table "quizzes"
#

INSERT INTO `quizzes` VALUES (1,1,'Pagsusulit sa Kabanata 1: Isang Pagtitipon');

#
# Structure for table "questions"
#

DROP TABLE IF EXISTS `questions`;
CREATE TABLE `questions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `quiz_id` int(11) NOT NULL,
  `question_text` text NOT NULL,
  `option_a` varchar(255) NOT NULL,
  `option_b` varchar(255) NOT NULL,
  `option_c` varchar(255) NOT NULL,
  `option_d` varchar(255) NOT NULL,
  `correct_answer` char(1) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `quiz_id` (`quiz_id`),
  CONSTRAINT `questions_ibfk_1` FOREIGN KEY (`quiz_id`) REFERENCES `quizzes` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

#
# Data for table "questions"
#

INSERT INTO `questions` VALUES (1,1,'Sino ang nagdaos ng isang malaking hapunan sa kaniyang bahay?','Padre Damaso','Kapitan Tiago','Don Rafael Ibarra','Padre Sibyla','B'),(2,1,'Saang kalye matatagpuan ang bahay kung saan idinaos ang pagtitipon?','Kalye Anloague','Kalye Escolta','Kalye Azcarraga','Kalye Magallanes','A'),(3,1,'Anong buwan idinaos ang nasabing pagtitipon?','Enero','Mayo','Oktubre','Disyembre','C'),(4,1,'Sino ang Pransiskanong pari na naging kura sa San Diego sa loob ng 20 taon?','Padre Sibyla','Padre Salvi','Padre Damaso','Padre Irene','C'),(5,1,'Ano ang tawag sa bulwagang tinutuluyan ng orkestra at komedor sa gabing iyon?','Azotea','Caida','Zaguan','Batalan','B'),(6,1,'Sino ang militar na nagkaroon ng mainit na pakikipagtalo kay Fray Damaso?','Tenyente Guevarra','Kapitan Heneral','Alperes','Isang Tenyente','D'),(7,1,'Ano ang pangunahing dahilan ng galit ni Fray Damaso sa gobyerno?','Kakulangan ng pagkain','Pagpapatalsik sa kaniya sa San Diego','Hindi pagkilala sa kaniyang awtoridad','Lahat ng nabanggit','B'),(8,1,'Anong ulam ang binanggit ni Fray Damaso na kinakain ng mga Indio?','Adobo','Sinigang','Tinola','Kare-kare','C'),(9,1,'Sino ang asawa ni Doktor de Espadana na mahilig magkolorete?','Donya Consolacion','Donya Victorina','Donya Pia Alba','Donya Teodora','B'),(10,1,'Ano ang naging paksa ng mainit na usapan nina Fray Damaso at ng militar?','Pagpapaalis ng bangkay ng isang erehe','Ang pagdating ni Crisostomo Ibarra','Ang mga reporma sa edukasyon','Ang buwis sa tabako','A');

#
# Structure for table "users"
#

DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `firebase_uid` varchar(255) NOT NULL,
  `first_name` varchar(100) NOT NULL,
  `last_name` varchar(100) NOT NULL,
  `email` varchar(255) DEFAULT NULL,
  `session_token` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `firebase_uid` (`firebase_uid`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

